export class AchievementManager {
	private achievements: Map<string, Achievement> = new Map();
	private modeBestScores: Record<string, number> = {};
	private diffBestScores: Record<string, number> = {};
	private totalTimePlayed = 0;
	private sessionTimePlayed = 0;
	private totalPowerUpsCollected = 0;
	onUnlock?: (achievement: Achievement) => void;

	constructor() {
		for (const def of ACHIEVEMENT_DEFS) {
			this.achievements.set(def.id, {
				id: def.id,
				title: def.title,
				description: def.desc,
				icon: def.icon,
				unlocked: false,
			});
		}
		this.load();
	}

	check(stats: GameStats): Achievement[] {
		const newlyUnlocked: Achievement[] = [];

		// Track mode and difficulty best scores
		const modeKey = stats.mode;
		this.modeBestScores[modeKey] = Math.max(this.modeBestScores[modeKey] ?? 0, stats.score);
		const diffKey = stats.difficulty;
		this.diffBestScores[diffKey] = Math.max(this.diffBestScores[diffKey] ?? 0, stats.score);
		this.totalPowerUpsCollected += stats.powerUpsCollected;

		for (const def of ACHIEVEMENT_DEFS) {
			const ach = this.achievements.get(def.id)!;
			if (ach.unlocked) continue;

			let earned = false;
			if (def.id === 'all-modes') {
				earned = (this.modeBestScores['classic'] ?? 0) >= 100 &&
				         (this.modeBestScores['speed'] ?? 0) >= 100 &&
				         (this.modeBestScores['maze'] ?? 0) >= 100 &&
				         (this.modeBestScores['wrap'] ?? 0) >= 100 &&
				         (this.modeBestScores['timeattack'] ?? 0) >= 100;
			} else if (def.id === 'all-diff') {
				earned = (this.diffBestScores['easy'] ?? 0) >= 200 &&
				         (this.diffBestScores['normal'] ?? 0) >= 200 &&
				         (this.diffBestScores['hard'] ?? 0) >= 200;
			} else if (def.id === 'power-10' || def.id === 'power-25') {
				const total = this.totalPowerUpsCollected;
				if (def.id === 'power-10') earned = total >= 10;
				else earned = total >= 25;
			} else {
				earned = def.check(stats);
			}

			if (earned) {
				ach.unlocked = true;
				ach.unlockedAt = Date.now();
				newlyUnlocked.push(ach);
			}
		}

		if (newlyUnlocked.length > 0) {
			this.save();
		}

		return newlyUnlocked;
	}

	updateTime(delta: number) {
		this.sessionTimePlayed += delta;
		this.totalTimePlayed += delta;
	}

	getTotalTime(): number { return this.totalTimePlayed; }

	getAll(): Achievement[] {
		return Array.from(this.achievements.values());
	}

	getUnlockedCount(): number {
		return Array.from(this.achievements.values()).filter(a => a.unlocked).length;
	}

	getTotalCount(): number {
		return this.achievements.size;
	}

	private save() {
		try {
			const data = {
				achievements: Array.from(this.achievements.entries()).filter(([, a]) => a.unlocked).map(([id, a]) => ({
					id,
					unlockedAt: a.unlockedAt,
				})),
				modeBestScores: this.modeBestScores,
				diffBestScores: this.diffBestScores,
				totalTimePlayed: this.totalTimePlayed,
				totalPowerUpsCollected: this.totalPowerUpsCollected,
			};
			localStorage.setItem('neon-snake-achievements', JSON.stringify(data));
		} catch {}
	}

	private load() {
		try {
			const raw = localStorage.getItem('neon-snake-achievements');
			if (!raw) return;
			const data = JSON.parse(raw);
			if (data.achievements) {
				for (const saved of data.achievements) {
					const ach = this.achievements.get(saved.id);
					if (ach) {
						ach.unlocked = true;
						ach.unlockedAt = saved.unlockedAt;
					}
				}
			}
			if (data.modeBestScores) this.modeBestScores = data.modeBestScores;
			if (data.diffBestScores) this.diffBestScores = data.diffBestScores;
			if (data.totalTimePlayed) this.totalTimePlayed = data.totalTimePlayed;
			if (data.totalPowerUpsCollected) this.totalPowerUpsCollected = data.totalPowerUpsCollected;
		} catch {}
	}
}

// Statistics tracking for Neon Snake VR

export interface SessionStats {
	longestSnake: number;
	fastestDeath: number;
	longestSurvival: number;
	totalDistance: number;
	totalTurns: number;
	classicBest: number;
	speedBest: number;
	mazeBest: number;
	wrapBest: number;
	dailyBest: number;
	timeattackBest: number;
	totalGames: number;
}

export class StatsTracker {
	private stats: SessionStats = {
		longestSnake: 0,
		fastestDeath: Infinity,
		longestSurvival: 0,
		totalDistance: 0,
		totalTurns: 0,
		classicBest: 0,
		speedBest: 0,
		mazeBest: 0,
		wrapBest: 0,
		dailyBest: 0,
		timeattackBest: 0,
		totalGames: 0,
	};

	constructor() {
		this.load();
	}

	updateAfterGame(score: number, length: number, survivalTime: number, distance: number, turns: number, mode: string) {
		this.stats.longestSnake = Math.max(this.stats.longestSnake, length);
		if (survivalTime > 0) {
			this.stats.fastestDeath = Math.min(this.stats.fastestDeath, survivalTime);
		}
		this.stats.longestSurvival = Math.max(this.stats.longestSurvival, survivalTime);
		this.stats.totalDistance += distance;
		this.stats.totalTurns += turns;
		this.stats.totalGames++;

		if (mode === 'classic') this.stats.classicBest = Math.max(this.stats.classicBest, score);
		else if (mode === 'speed') this.stats.speedBest = Math.max(this.stats.speedBest, score);
		else if (mode === 'maze') this.stats.mazeBest = Math.max(this.stats.mazeBest, score);
		else if (mode === 'wrap') this.stats.wrapBest = Math.max(this.stats.wrapBest, score);
		else if (mode === 'daily') this.stats.dailyBest = Math.max(this.stats.dailyBest, score);
		else if (mode === 'timeattack') this.stats.timeattackBest = Math.max(this.stats.timeattackBest, score);

		this.save();
	}

	getStats(): SessionStats { return { ...this.stats }; }

	private save() {
		try {
			localStorage.setItem('neon-snake-stats', JSON.stringify(this.stats));
		} catch {}
	}

	private load() {
		try {
			const raw = localStorage.getItem('neon-snake-stats');
			if (raw) {
				const saved = JSON.parse(raw);
				Object.assign(this.stats, saved);
			}
		} catch {}
	}
}

// Procedural audio for Neon Snake VR
// Uses Web Audio API for retro synth sounds

export class AudioManager {
	private ctx: AudioContext | null = null;
	private masterGain: GainNode | null = null;
	private volume = 0.5;
	private muted = false;

	init() {
		if (this.ctx) return;
		try {
			this.ctx = new AudioContext();
			this.masterGain = this.ctx.createGain();
			this.masterGain.gain.value = this.volume;
			this.masterGain.connect(this.ctx.destination);
		} catch {}
	}

	setVolume(v: number) {
		this.volume = Math.max(0, Math.min(1, v));
		if (this.masterGain) this.masterGain.gain.value = this.muted ? 0 : this.volume;
	}

	toggleMute(): boolean {
		this.muted = !this.muted;
		if (this.masterGain) this.masterGain.gain.value = this.muted ? 0 : this.volume;
		return this.muted;
	}

	isMuted(): boolean { return this.muted; }

	private playTone(freq: number, duration: number, type: OscillatorType = 'square', vol = 0.3) {
		if (!this.ctx || !this.masterGain) return;
		const osc = this.ctx.createOscillator();
		const gain = this.ctx.createGain();
		osc.type = type;
		osc.frequency.value = freq;
		gain.gain.setValueAtTime(vol, this.ctx.currentTime);
		gain.gain.exponentialRampToValueAtTime(0.001, this.ctx.currentTime + duration);
		osc.connect(gain);
		gain.connect(this.masterGain);
		osc.start();
		osc.stop(this.ctx.currentTime + duration);
	}

	playEat(combo: number) {
		if (!this.ctx) this.init();
		// Rising pitch for combos
		const baseFreq = 440 + combo * 80;
		this.playTone(baseFreq, 0.15, 'square', 0.25);
		setTimeout(() => this.playTone(baseFreq * 1.5, 0.1, 'square', 0.2), 50);
	}

	playMove() {
		if (!this.ctx) this.init();
		this.playTone(120, 0.04, 'square', 0.05);
	}

	playDeath() {
		if (!this.ctx) this.init();
		// Descending tones
		const freqs = [440, 330, 220, 110];
		freqs.forEach((f, i) => {
			setTimeout(() => this.playTone(f, 0.2, 'sawtooth', 0.3), i * 100);
		});
	}

	playStart() {
		if (!this.ctx) this.init();
		this.playTone(330, 0.1, 'square', 0.2);
		setTimeout(() => this.playTone(440, 0.1, 'square', 0.2), 100);
		setTimeout(() => this.playTone(660, 0.15, 'square', 0.25), 200);
	}

	playMenuSelect() {
		if (!this.ctx) this.init();
		this.playTone(550, 0.08, 'sine', 0.15);
	}

	playPause() {
		if (!this.ctx) this.init();
		this.playTone(300, 0.15, 'triangle', 0.15);
	}

	playAchievement() {
		if (!this.ctx) this.init();
		const melody = [523, 659, 784, 1047];
		melody.forEach((f, i) => {
			setTimeout(() => this.playTone(f, 0.2, 'sine', 0.2), i * 120);
		});
	}

	playCombo(count: number) {
		if (!this.ctx) this.init();
		const freq = 600 + count * 100;
		this.playTone(freq, 0.1, 'square', 0.2);
		setTimeout(() => this.playTone(freq * 1.25, 0.15, 'square', 0.25), 60);
	}

	playPowerUp() {
		if (!this.ctx) this.init();
		this.playTone(880, 0.08, 'sine', 0.25);
		setTimeout(() => this.playTone(1100, 0.08, 'sine', 0.25), 60);
		setTimeout(() => this.playTone(1320, 0.12, 'sine', 0.3), 120);
	}

	playLevelUp() {
		if (!this.ctx) this.init();
		const notes = [440, 550, 660, 880, 1100];
		notes.forEach((f, i) => {
			setTimeout(() => this.playTone(f, 0.12, 'triangle', 0.2), i * 80);
		});
	}
}

